UPDATE Kitaplar SET Yayinevi = 'Can Yayınları', BasimYili = 1951, Aciklama = 'İnsanın evrendeki anlamsızlığa karşı koyuşunun tek yolunun "isyan" olduğunu, ancak bu isyanın bir cinayete veya diktatörlüğe dönüşmemesi gerektiğini tartışan metafizik analiz.' WHERE KitapAdi = 'Başkaldıran İnsan';

