UPDATE Kitaplar SET Yayinevi = 'Kolektif Kitap', BasimYili = 2018, Aciklama = 'Sahte haberler, teknolojik işsizlik, göçmen krizleri ve ekolojik çöküş gibi günümüzün en yakıcı küresel sorunlarına tarihsel ve felsefi bir mercekten bakan derin bir analiz.' WHERE KitapAdi = '21. Yüzyıl İçin 21 Ders';
UPDATE Kitaplar SET Yayinevi = 'Kronik Kitap', BasimYili = 2019, Aciklama = 'İlber Ortaylı''nın kendi deneyimlerinden yola çıkarak, seyahat etmek, dil öğrenmek, meslek seçimi ve müzik zevki gibi konularda gençlere ufuk açıcı bir yaşam rehberi sunduğu söyleşi kitabı.' WHERE KitapAdi = 'Bir Ömür Nasıl Yaşanır?';
UPDATE Kitaplar SET Yayinevi = 'Kronik Kitap', BasimYili = 2018, Aciklama = 'İlber Ortaylı''nın kaleminden, Mustafa Kemal Atatürk''ün askeri dehasını, vizyonunu, Cumhuriyet''i kurarken verdiği siyasi mücadeleleri tarihi belgeler ışığında anlatan muazzam biyografi.' WHERE KitapAdi = 'Gazi Mustafa Kemal Atatürk';
